import Vue from 'vue';
import Router from 'vue-router';
import index from '@/pages/index';

Vue.use(Router);

export default new Router({
  routes: [
    {
      path: '/',
      name: '首页',
      component: index
    },
    {
      path: '/login',
      name: '登录',
      component: resolve => require(['@/pages/login'], resolve)
    }
  ]
});



