<template>
  <div class="index">
    <div class="indexWrapper">
      <div class="indexWrapper-top">
        <img src="~@/assets/images/logo.png" alt="" height="65">
      </div>
      <div class="indexWrapper-bottom">
        <p>请选择您要登陆的平台</p>
        <div class="indexWrapper-bottom-selectWrapper">
          <div class="indexWrapper-bottom-selectWrapper-item" v-for="(item,index) in entrances" :key=index @click='selectEntrances(item.tag)'>
            <img :src="item.img" alt="">
            <p>{{ item.name }}</p>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import lazyImg from "../assets/images/indexBackGround.jpg";

export default {
  data() {
    return {
      entrances: [
        {
          img:
            "https://timgsa.baidu.com/timg?image&quality=80&size=b9999_10000&sec=1544257899375&di=ffe741ad7244dbfda8198deae488a434&imgtype=0&src=http%3A%2F%2Fpic.51yuansu.com%2Fpic3%2Fcover%2F01%2F11%2F85%2F5903b0f5c1967_610.jpg",
          name: "工作平台",
          tag: "1"
        },
        {
          img:
            "https://timgsa.baidu.com/timg?image&quality=80&size=b9999_10000&sec=1544245468355&di=34b7d23084abbe8799fb3574bc8753aa&imgtype=0&src=http%3A%2F%2Fpaper.taizhou.com.cn%2Ftzsb%2Fres%2F1%2F3%2F2017-01%2F19%2F12%2Fres01_attpic_brief.jpg",
          name: "监管平台",
          tag: "2"
        },
        {
          img:
            "https://timgsa.baidu.com/timg?image&quality=80&size=b9999_10000&sec=1544245495090&di=a738fabf1c63363f3bc7b42c009fffa3&imgtype=0&src=http%3A%2F%2Fimgsrc.baidu.com%2Fimgad%2Fpic%2Fitem%2F8d5494eef01f3a297bd2d6cf9325bc315c607c9c.jpg",
          name: "公开平台",
          tag: "3"
        }
      ]
    };
  },
  mounted() {
    this.isCompleteLoadBgImage();
  },
  methods: {
    isCompleteLoadBgImage() {
      const obj = document.querySelector(".index");
      const imgObj = new Image();
      imgObj.src = lazyImg;
      imgObj.onload = () => {
        obj.style.background = ` url('${lazyImg}') no-repeat center`;
        obj.style.backgroundSize = "100% auto";
      };
    },
    selectEntrances(tag) {
      this.$router.push(`/login?tag=${tag}`);
    }
  }
};
</script>

<style scoped lang="stylus">
.index {
  width: 100%;
  height: 100%;
  background: url('~@/assets/images/lazy_indexBackGround.jpg') no-repeat center;
  background-size: 100% auto;
  position: relative;
  overflow: hidden;

  .indexWrapper {
    position: absolute;
    width: 450px;
    height: 564px;
    background: #fff;
    box-shadow: 2px 2px 56px rgba(0, 0, 0, 0.13);
    top: 50%;
    left: 50%;
    transform: translateY(-50%) translateX(-50%);
    border-radius: 3px;

    .indexWrapper-top {
      text-align: center;
      padding: 50px;
    }

    .indexWrapper-bottom {
      & p:first-child {
        color: #212121;
        font-size: 19px;
        font-weight: 800;
        text-align: center;
      }

      .indexWrapper-bottom-selectWrapper {
        display: flex;
        padding: 70px 0;

        .indexWrapper-bottom-selectWrapper-item {
          flex: 1;
          justify-content: center;
          justify-items: center;
          text-align: center;
          opacity: 0.5;
          cursor: pointer;

          &:hover {
            opacity: 1;
          }

          img {
            width: 100px;
            height: 100px;
            border-radius: 50%;
          }

          p {
            font-weight: 500;
            color: #666;
          }
        }
      }
    }
  }
}
</style>



